const Q_ECONOMICS_2009=[{"id": "objective>Economics>2009>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Musa has a choice of buying a shirt, a book and a bag. What is the opportunity cost of buying a book?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">A bag only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">A book and a bag</div>", "<div style=\"font-family:Cambria;font-size:17px;\">A shirt and a bag</div>", "<div style=\"font-family:Cambria;font-size:17px;\">A shirt only </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Opportunity cost is alternative foregone. Therefore, the opportunity cost will be the shirt and the bag he did not buy.</div>", "topic": "THEORY OF CONSUMER BEHAVIOUR : CONCEPT"}, {"id": "objective>Economics>2009>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A typical feature of a market economy is that </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">all producers make profit </div>", "<div style=\"font-family:Cambria;font-size:17px;\">full employment exists</div>", "<div style=\"font-family:Cambria;font-size:17px;\">consumer sovereignty exists</div>", "<div style=\"font-family:Cambria;font-size:17px;\">there is equality of economic agents</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A free market or capitalist economy is an economy in which all means of production are controlled by a private indivdual. In this market, there is consumer sovereign i.e the consumer has a freedom of choice.</div>", "topic": "ECONOMIC SYSTEM : TYPES AND FEATURES OF ECONOMIC SYSTEM"}, {"id": "objective>Economics>2009>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The privatization exercise in Nigeria is a move towards a</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">mixed economy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">subsistence economy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">market economy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">command economy</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Privatization is the process of transferring an enterprise or industry from the public sector to the private sector. The public sector is the part of the economic system that is run by government agencies. The underlying logic of privatization is that privately run enterprises are more efficient, better managed, and more customer-oriented than their public sector counterparts. Therefore, privatization is a move towards a market economy, where decisions regarding investment, production, and distribution are primarily determined by the interplay of supply and demand and are made on a voluntary basis.</div>", "topic": "INDUSTRY & INDUSTRIALISATION : COMMERCIALISATION & PRIVATISATION"}, {"id": "objective>Economics>2009>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><strong>Use the pie chart below to answer this question</strong>  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The percentage contribution of the transport sector is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">600.0</div>", "<div style=\"font-family:Cambria;font-size:17px;\">166.7</div>", "<div style=\"font-family:Cambria;font-size:17px;\">60.0</div>", "<div style=\"font-family:Cambria;font-size:17px;\">16.7</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Transport</td><td style=\"text-align:center;\">sector</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">60<hr size=\"1\" />360</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">100<hr size=\"1\" />1</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">100<hr size=\"1\" />6</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">16.7%</td></tr></table></div></div>", "topic": "ECONOMIC DEVELOPMENT : INDICATORS OF GROWTH & DEVELOPMENT"}, {"id": "objective>Economics>2009>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <strong>Use the pie chart below to answer this question</strong>  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> If the contribution of the oil sector is ₦3.6 million, what is the contribution of the other sectors?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">₦10.8 million</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦7.2 million</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦3.6 million</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦2.4 million</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Oil sector = 3.6 <br/> Total sectors = 3.6 x 3 <br/>                             = 10.8 <br/> Therefore, other sectors = 10.8 - 3.6 <br/>                                           = 7.2</div>", "topic": "ECONOMIC DEVELOPMENT : INDICATORS OF GROWTH & DEVELOPMENT"}, {"id": "objective>Economics>2009>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A cumulative frequency graph is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a histogram </div>", "<div style=\"font-family:Cambria;font-size:17px;\">an ogive</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a bar chart</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a pie chart</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A cumulative frequency graph, also known as an Ogive, is a curve showing the cumulative frequency for a given set of data.</div>", "topic": "TOOLS FOR ECONOMIC ANALYSIS : MEASURE OF DISPERSION"}, {"id": "objective>Economics>2009>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A movement along the same demand curve is caused by the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">price of the product</div>", "<div style=\"font-family:Cambria;font-size:17px;\">price of other products</div>", "<div style=\"font-family:Cambria;font-size:17px;\">income of the consumer</div>", "<div style=\"font-family:Cambria;font-size:17px;\">taste of the consumer</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It is caused by the price of the product. Price is the major determinant of a change in  quantity demanded or movement along the same demand curve.</div>", "topic": "THE THEORY OF DEMAND : MEANING AND DETERMINANTS"}, {"id": "objective>Economics>2009>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The demand curve for a luxury good is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">negatively sloped </div>", "<div style=\"font-family:Cambria;font-size:17px;\">parallel to the price axis</div>", "<div style=\"font-family:Cambria;font-size:17px;\">parallel to the quantity axis</div>", "<div style=\"font-family:Cambria;font-size:17px;\">positively sloped</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The demand curve for a luxury good is negatively sloped. This is because as the price of a luxury good increases, the quantity demanded decreases, and vice versa. This is in line with the law of demand which states that there is an inverse relationship between price and quantity demanded, ceteris paribus (all other things being equal).</div>", "topic": "THE THEORY OF DEMAND : ELASTICITY OF DEMAND"}, {"id": "objective>Economics>2009>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Price elasticity of demand is expressed as </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">percentage change in price/percentage change in quantity demanded</div>", "<div style=\"font-family:Cambria;font-size:17px;\">percentage change in quantity demanded/percentage change in income</div>", "<div style=\"font-family:Cambria;font-size:17px;\">percentage change in income/percentage change in quantity demanded</div>", "<div style=\"font-family:Cambria;font-size:17px;\">percentage change in quantity demanded/percentage change in price </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Price elasticity of demand is calculated as: Percentage change in quantity demanded / Percentage change in price. </div>", "topic": "THE THEORY OF DEMAND : ELASTICITY OF DEMAND"}, {"id": "objective>Economics>2009>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A major assumption in cardinal utility theory is that </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">utility is measurable</div>", "<div style=\"font-family:Cambria;font-size:17px;\">utility is not measurable</div>", "<div style=\"font-family:Cambria;font-size:17px;\">total utility equals marginal utility </div>", "<div style=\"font-family:Cambria;font-size:17px;\">total utility is constant</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Cardinal utility is a view of utility measurement based on the presumption that the satisfaction of wants and needs is a quantifiable characteristic of human activity. In other words, utility can be measured with numerical values (1, 2, 3, etc.) along a scale.  Cardinal utility presumes that satisfaction is a measurable characteristic of a person, like height or weight. The contrasting notion is ordinal utility, which is based on a ranking of preferences.</div>", "topic": "THEORY OF CONSUMER BEHAVIOUR : UTILITY SCHOOL OF THOUGHT"}, {"id": "objective>Economics>2009>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A supply curve is positively sloped because </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">supply always exceeds demand</div>", "<div style=\"font-family:Cambria;font-size:17px;\">demand always exceeds supply</div>", "<div style=\"font-family:Cambria;font-size:17px;\">price is an incentive to consumers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">price is an incentive to producers</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Because the marginal cost curve is positively sloped due to the law of diminishing marginal returns, so too is the firm's supply curve. And because all firm's in a perfectly competitive industry have positively-sloped marginal cost curves, the market supply curve for the entire industry is also positively sloped.</div>", "topic": "THEORY OF SUPPLY : MEANING AND DETERMINANTS"}, {"id": "objective>Economics>2009>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The short-run supply curve for medical doctors is more likely to be </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">perfectly elastic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">perfectly inelastic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fairly inelastic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fairly elastic</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The short-run supply curve for medical doctors is more likely to be fairly inelastic. This is because the supply of doctors cannot be quickly increased or decreased in response to changes in price. It takes a long time to train a doctor, so the supply is relatively fixed in the short run. Therefore, the supply curve is inelastic, meaning it does not respond significantly to changes in price.</div>", "topic": "THEORY OF SUPPLY : ELASTICITY OF SUPPLY"}, {"id": "objective>Economics>2009>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If the price of an item changes by 8% and quantity supplied changes from 600 units to 660 units, the price elasticity of supply is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.80</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.25</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.00</div>", "<div style=\"font-family:Cambria;font-size:17px;\">10.00</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">%</td><td style=\"text-align:center;\">Δ</td><td style=\"text-align:center;\">Qs</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">660 - 600<hr size=\"1\" />600</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">100<hr size=\"1\" />1</td></tr></table></div> <br/>  <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">60<hr size=\"1\" />600</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">100<hr size=\"1\" />1</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">10</td></tr></table></div>  <br/>  P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">ED</span> = 10/8 = 1.25</div>", "topic": "THEORY OF SUPPLY : ELASTICITY OF SUPPLY"}, {"id": "objective>Economics>2009>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In a regulated market, price is determined by </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">consumers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">producers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">auction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">government</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A regulated market or controlled market, is a market where the government controls the forces of supply and demand, such as who is allowed to enter the market or what prices may be charged.</div>", "topic": "THE THEORY OF PRICE DETERMINATION : DETERMINANTS OF PRICE UNDER FREE MARKET"}, {"id": "objective>Economics>2009>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A decrease in supply without a corresponding change in demand will lead to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">an increase in equilibrium price and a decrease in equilibrium quantity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a decrease in equilibrium price and an increase in equilibrium quantity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a decrease in equilibrium price and equilibrium quantity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an increase in equilibrium price and quantity </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">If there is a decrease in supply when demand remains constant,  there will be an excess demand over supply. This will lead to increase in equilibrium price and decrease in equilibrium quantity.</div>", "topic": "THE THEORY OF PRICE DETERMINATION : EFFECT OF CHANGE IN SUPPLY & DEMAND ON EQUILIBRIUM PRICE & QUANTITY"}, {"id": "objective>Economics>2009>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Production takes place when </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">output is transformed into input </div>", "<div style=\"font-family:Cambria;font-size:17px;\">machines replace human effort</div>", "<div style=\"font-family:Cambria;font-size:17px;\">input is transformed into output </div>", "<div style=\"font-family:Cambria;font-size:17px;\">there is specialization and division of labour </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It takes place when input is transformed into output.production takes place when raw materials is transform into finished goods and finally distributed to consumers.</div>", "topic": "THEORY OF PRODUCTION (2) : CONCEPTS OF PRODUCTION"}, {"id": "objective>Economics>2009>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><strong>Use the table below to answer this question </strong>  <br/>  <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\">Unit of capital</td><td style=\"border:1px solid black;text-align:center;\">Total output (kg)</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">1</td><td style=\"border:1px solid black;text-align:center;\">16</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">2</td><td style=\"border:1px solid black;text-align:center;\">64</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">3</td><td style=\"border:1px solid black;text-align:center;\">126</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">4</td><td style=\"border:1px solid black;text-align:center;\">212</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">5</td><td style=\"border:1px solid black;text-align:center;\">425</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">6</td><td style=\"border:1px solid black;text-align:center;\">884</td></tr></table></div> <br/>  <br/> The marginal product of the 5th unit of capital is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">42</div>", "<div style=\"font-family:Cambria;font-size:17px;\">85</div>", "<div style=\"font-family:Cambria;font-size:17px;\">114</div>", "<div style=\"font-family:Cambria;font-size:17px;\">213</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The marginal product of the 5th unit of capital is the difference in total output when the capital is increased from 4 units to 5 units. From the table, the total output for 4 units of capital is 212kg and for 5 units of capital is 425kg. Therefore, the marginal product of the 5th unit of capital is 425 - 212 = 213kg.</div>", "topic": "THEORY OF PRODUCTION (2) : LAWS OF PRODUCTION"}, {"id": "objective>Economics>2009>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <strong>Use the table below to answer this question </strong>  <br/>  <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\">Unit of capital</td><td style=\"border:1px solid black;text-align:center;\">Total output (kg)</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">1</td><td style=\"border:1px solid black;text-align:center;\">16</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">2</td><td style=\"border:1px solid black;text-align:center;\">64</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">3</td><td style=\"border:1px solid black;text-align:center;\">126</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">4</td><td style=\"border:1px solid black;text-align:center;\">212</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">5</td><td style=\"border:1px solid black;text-align:center;\">425</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">6</td><td style=\"border:1px solid black;text-align:center;\">884</td></tr></table></div> <br/> Determine the average product of the 4th unit of capital </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">53</div>", "<div style=\"font-family:Cambria;font-size:17px;\">86</div>", "<div style=\"font-family:Cambria;font-size:17px;\">212</div>", "<div style=\"font-family:Cambria;font-size:17px;\">213</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The average product of the 4th unit of capital is the total output when 4 units of capital are used divided by the number of units of capital used. From the table, the total output for 4 units of capital is 212kg. Therefore, the average product of the 4th unit of capital is 212 / 4 = 53kg.</div>", "topic": "THEORY OF PRODUCTION (2) : LAWS OF PRODUCTION"}, {"id": "objective>Economics>2009>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following can be deduced from the law of variable proportions when total output is rising?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">MP is greater than AP</div>", "<div style=\"font-family:Cambria;font-size:17px;\">MP is less than AP</div>", "<div style=\"font-family:Cambria;font-size:17px;\">MP is equal to AP</div>", "<div style=\"font-family:Cambria;font-size:17px;\">MP is equal to zero</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The law of variable proportions states that as more of a variable input (like labor) is added to a fixed input (like capital), the additional output or the marginal product (MP) will at first increase, then it will eventually decrease. This is also known as the law of diminishing returns. When total output is rising, it means we are in the stage where the addition of more variable input is still increasing the output, hence the MP is greater than the average product (AP).</div>", "topic": "THEORY OF PRODUCTION (2) : LAWS OF PRODUCTION"}, {"id": "objective>Economics>2009>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">As the level of output increases, the average fixed cost of a firm will</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">continue to increase </div>", "<div style=\"font-family:Cambria;font-size:17px;\">remain unchanged</div>", "<div style=\"font-family:Cambria;font-size:17px;\">continue to decrease </div>", "<div style=\"font-family:Cambria;font-size:17px;\">be equal to the total cost</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The average fixed cost curve is negatively sloped. Average fixed cost is relatively high at small quantities of output, then declines as production increases. The more production increases, then the more average fixed cost declines. The reason behind this perpetual decline is that a given fixed cost is spread over an increasingly larger quantity of output.</div>", "topic": "THE CONCEPT OF COST & REVENUE : SHORT RUN & LONG RUN COST"}, {"id": "objective>Economics>2009>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The shape of the long-run average cost curve is best explained by the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">law of diminishing returns</div>", "<div style=\"font-family:Cambria;font-size:17px;\">law of returns to scale</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cost of fixed inputs</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cost of variable inputs</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The long-run average cost (LRAC) curve is a U-shaped curve that shows all possible output levels plotted against the average cost for each level. The LRAC is an \"envelope\" that contains all possible short-run average total cost (ATC) curves for the firm. It is made up of all ATC curve tangency points. All ATC curves are short-run curves. The shape of the LRAC is explained using the law of returns to scale.</div>", "topic": "THEORY OF PRODUCTION (2) : PRODUCTION FUNCTIONS & LAWS OF RETURNS"}, {"id": "objective>Economics>2009>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The supply curve of a perfectly competitive firm is identical to its</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">total cost</div>", "<div style=\"font-family:Cambria;font-size:17px;\">marginal cost</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fixed cost </div>", "<div style=\"font-family:Cambria;font-size:17px;\">variable cost </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In a profit-maximizing firm, the quantity of output that equates marginal revenue and marginal cost (MR = MC) and is characterized by the equality between price and marginal revenue (P = MR).</div>", "topic": "MARKET STRUCTURE : PERFECT MARKET"}, {"id": "objective>Economics>2009>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If the monopolist is incurring short-run losses, this means that his </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">selling price is above the short-run marginal cost</div>", "<div style=\"font-family:Cambria;font-size:17px;\">selling price is below the short-run marginal cost </div>", "<div style=\"font-family:Cambria;font-size:17px;\">average revenue is greater than marginal revenue </div>", "<div style=\"font-family:Cambria;font-size:17px;\">average revenue is less than marginal revenue</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the short run, if a monopolist is incurring losses, it means that the selling price is below the short-run marginal cost. Marginal cost is the cost of producing one more unit of a good. If the selling price is below this cost, the monopolist is not covering its costs and is therefore making a loss.</div>", "topic": "MARKET STRUCTURE : IMPERFECT MARKET ( MONOPOLY)"}, {"id": "objective>Economics>2009>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In the long run, one of the characteristics of monopolistic competitive firms is that they </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">make abnormal profits</div>", "<div style=\"font-family:Cambria;font-size:17px;\">suffer losses</div>", "<div style=\"font-family:Cambria;font-size:17px;\">make normal profits</div>", "<div style=\"font-family:Cambria;font-size:17px;\">collude with each other</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the long run, one of the characteristics of monopolistic competitive firms is that they make normal profits. This is because in the long run, firms have the ability to enter and exit the market freely. If firms were making abnormal profits, new firms would enter the market, increasing competition and driving down prices until only normal profits were being made. Similarly, if firms were making losses, some firms would exit the market, reducing competition and driving up prices until only normal profits were being made.</div>", "topic": "MARKET STRUCTURE : MONOPOLISTIC COMPETITION"}, {"id": "objective>Economics>2009>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In developing countries, it is easier to obtain accurate national income estimates through the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">GNP</div>", "<div style=\"font-family:Cambria;font-size:17px;\">GDP</div>", "<div style=\"font-family:Cambria;font-size:17px;\">NDP</div>", "<div style=\"font-family:Cambria;font-size:17px;\">NNP</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The GDP is used to measure the growth rate in an economy since it excludes income from abroad.Therefore, national income can be properly estimated and calculated.</div>", "topic": "NATIONAL INCOME : MEASUREMENT OF NATIONAL INCOME"}, {"id": "objective>Economics>2009>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Double counting is a problem in computing national income when using the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">expenditure method</div>", "<div style=\"font-family:Cambria;font-size:17px;\">income method</div>", "<div style=\"font-family:Cambria;font-size:17px;\">output method </div>", "<div style=\"font-family:Cambria;font-size:17px;\">value-added method</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Double counting is a problem in computing national income when using the output method. The output method, also known as the production method, involves calculating the total value of goods and services produced in a country. However, this method can lead to double counting because it counts the value of intermediate goods (goods used in the production of other goods) as well as the value of final goods. This results in an overestimation of the national income. The value-added method is a way to avoid double counting by only counting the value added at each stage of production.</div>", "topic": "NATIONAL INCOME : MEASUREMENT OF NATIONAL INCOME"}, {"id": "objective>Economics>2009>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In the circular flow of income, an increase in savings causes</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">an increase in imports</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a decrease in the income stream</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an increase in household consumption</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a decrease in exports</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the circular flow of income model, savings is a leakage or withdrawal from the income stream. When savings increase, it means that less money is being spent in the economy, which leads to a decrease in the income stream. This is because the money that is saved is not being used for consumption or investment, which are the main drivers of economic activity and income generation.</div>", "topic": "NATIONAL INCOME : CONCEPT"}, {"id": "objective>Economics>2009>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The ability of commercial banks to create money depends on the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">reserve ratio</div>", "<div style=\"font-family:Cambria;font-size:17px;\">liquidity ratio</div>", "<div style=\"font-family:Cambria;font-size:17px;\">interest rate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">capital base</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The ability of commercial banks to create money is largely dependent on the reserve ratio. The reserve ratio is the portion of depositors' balances that banks must have on hand as cash. This rate is often set by the central bank and it determines the amount of deposits that a bank can lend out. If the reserve ratio is low, banks can lend more money and thus create more money. Conversely, if the reserve ratio is high, banks can lend less money and thus create less money.</div>", "topic": "FINANCIAL INSTITUTION : COMMERCIAL BANKS"}, {"id": "objective>Economics>2009>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The reform in banking sector in Nigeria is principally motivated by the need to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">increase the capital base of banks</div>", "<div style=\"font-family:Cambria;font-size:17px;\">provide more money to run the economy </div>", "<div style=\"font-family:Cambria;font-size:17px;\">minimize the rate of bank failures </div>", "<div style=\"font-family:Cambria;font-size:17px;\">enhance efficiency in bank operations</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Financial reforms as defined by Ebong (2006) are deliberate policy response to correct perceived or impending financial crises and subsequent failure. <br/>  <br/> Financial sector reforms are an integral part of the economic reform package. Therefore involved packaging the liberalization of interest rates, promotion of market-bases system of credit allocation, enhancing competition, and efficiency of the regulatory and supervisory framework. <br/>  Financial sector reforms in Nigeria were motivated by the need to productively put the Nigerian banking industryand the economy at large on the path of global competitiveness. It can be concluded that no economy can ever develop without an appreciable growth in the financial sector.</div>", "topic": "FINANCIAL INSTITUTION : COMMERCIAL BANKS"}, {"id": "objective>Economics>2009>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A manufacturer who wants to build a new plant will source funds from the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">commercial banks</div>", "<div style=\"font-family:Cambria;font-size:17px;\">money market</div>", "<div style=\"font-family:Cambria;font-size:17px;\">capital market</div>", "<div style=\"font-family:Cambria;font-size:17px;\">government</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A manufacturer who wants to build a new plant will source funds from the capital market. The capital market is a part of the financial system where long-term securities such as stocks and bonds are bought and sold. It is the ideal place for a manufacturer to raise funds for a long-term project like building a new plant. Commercial banks and the money market deal with short-term funds, while the government is not typically a source of business financing.</div>", "topic": "FINANCIAL INSTITUTION : DEVELOPMENT, MERCHANT, MORTGAGE BANK ETC"}, {"id": "objective>Economics>2009>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Cost-push inflation occurs when</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">production cost is high</div>", "<div style=\"font-family:Cambria;font-size:17px;\">factor prices decrease</div>", "<div style=\"font-family:Cambria;font-size:17px;\">there is too much money in circulation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">government embarks on deficit financing</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Cost push inflation is inflation caused by an increase in prices of inputs like labour, raw material, etc. The increased price of the factors of production leads to a decreased supply of these goods.</div>", "topic": "INFLATION & DEFLATION : CAUSES & CONTROL"}, {"id": "objective>Economics>2009>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If government expenditure exceeds revenue, this results in </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">balanced budget</div>", "<div style=\"font-family:Cambria;font-size:17px;\">national debt</div>", "<div style=\"font-family:Cambria;font-size:17px;\">budget deficit</div>", "<div style=\"font-family:Cambria;font-size:17px;\">budget surplus</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Where annual expenses of a budget exceeds the annual income of the budget then it is known as budget deficit indicating financial unhealthiness of a country which can be reduced by taking the attempts of different measures like reduction of revenue outflow and increasing revenue inflow.</div>", "topic": "PUBLIC FINANCE : BUDGET"}, {"id": "objective>Economics>2009>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The Basic Need Approach to development is directed at</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">poverty alleviation </div>", "<div style=\"font-family:Cambria;font-size:17px;\">provision of educational infrastructure</div>", "<div style=\"font-family:Cambria;font-size:17px;\">provision of health services</div>", "<div style=\"font-family:Cambria;font-size:17px;\">improvement in workers' income</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The basic needs approach is one of the major approaches to the measurement of absolute poverty in developing countries. It attempts to define the absolute minimum resources necessary for long-term physical well-being, usually in terms of consumption goods. The poverty line is then defined as the amount of income required to satisfy those needs.</div>", "topic": "ECONOMIC DEVELOPMENT : DEVELOPMENT PLANNING"}, {"id": "objective>Economics>2009>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The major reason why countries strive to achieve optimum growth is to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">be self-sufficient</div>", "<div style=\"font-family:Cambria;font-size:17px;\">raise general living standards</div>", "<div style=\"font-family:Cambria;font-size:17px;\">raise the level of production</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reduce aggregate expenditure</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Optimum growth in an economy refers to the highest possible rate of growth that an economy can sustain without running into resource constraints or inflaming inflation. The main reason why countries strive to achieve optimum growth is to raise general living standards. Higher economic growth leads to higher income levels and therefore higher living standards.</div>", "topic": "ECONOMIC DEVELOPMENT : INDICATORS OF GROWTH & DEVELOPMENT"}, {"id": "objective>Economics>2009>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">According to the theory of comparative advantage, specialization will result in</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">labour-intensive method of production</div>", "<div style=\"font-family:Cambria;font-size:17px;\">capital-intensive method of production</div>", "<div style=\"font-family:Cambria;font-size:17px;\">efficient allocation of resources</div>", "<div style=\"font-family:Cambria;font-size:17px;\">efficient distribution of output</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Production specialization according to comparative advantage, not absolute advantage, results in exchange opportunities that lead to consumption opportunities beyond the PPC. Trade between two agents or countries allows the countries to enjoy a higher total output and level of consumption than what would have been possible domestically. It will result in reduction of cost, and efficient allocation of resources.</div>", "topic": "INTERNATIONAL TRADE : PRINCIPLES OF INTERNATIONAL TRADE"}, {"id": "objective>Economics>2009>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Dumping in international trade means selling a good at a </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">higher price at home than abroad </div>", "<div style=\"font-family:Cambria;font-size:17px;\">lower price at home than abroad</div>", "<div style=\"font-family:Cambria;font-size:17px;\">price that equates marginal cost with marginal revenue</div>", "<div style=\"font-family:Cambria;font-size:17px;\">price above marginal cost abroad</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Dumping is an international price discrimination in which an exporter firm sells a portion of its output in a foreign market at a very low price and the remaining output at a high price in the home market. <br/> Haberler defines dumping as: \"The sale of goods abroad at a price which is lower than the selling price of the same</div>", "topic": "INTERNATIONAL TRADE : TERMS OF TRADE"}, {"id": "objective>Economics>2009>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Guided deregulation as currently practised in Nigeria implies that</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">market forces determine interest and exchange rates</div>", "<div style=\"font-family:Cambria;font-size:17px;\">government alone determines interests and exchange rates</div>", "<div style=\"font-family:Cambria;font-size:17px;\">market forces and government determine interest and exchange rates</div>", "<div style=\"font-family:Cambria;font-size:17px;\">exchange rate is regulated while interest rate is fixed </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Deregulation means that the Government will no longer continue to be the main supplier of a particular Products, but will encourage private sector to take over the role of supplying Products as well.</div>", "topic": "FINANCIAL INSTITUTION : COMMERCIAL BANKS"}, {"id": "objective>Economics>2009>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An important function of the World Bank is to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">provide short-run loans to members</div>", "<div style=\"font-family:Cambria;font-size:17px;\">encourage trade between members</div>", "<div style=\"font-family:Cambria;font-size:17px;\">promote capital-intensive production</div>", "<div style=\"font-family:Cambria;font-size:17px;\">provide long-term loans to members</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The World Bank is an international financial institution that provides loans and grants to the governments of poorer countries for the purpose of pursuing capital projects. It comprises two institutions: the International Bank for Reconstruction and Development (IBRD), and the International Development Association (IDA). The World Bank is a component of the World Bank Group. The World Bank's most recent stated goal is the reduction of poverty. It does this by providing long-term loans to member countries for developmental projects.</div>", "topic": "INTERNATIONAL ECONOMIC ORGANISATION : IBRD, AFDB, UNCTAD ETC"}, {"id": "objective>Economics>2009>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The major problem confronting a sole proprietor is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">high level of risk </div>", "<div style=\"font-family:Cambria;font-size:17px;\">limited expertise</div>", "<div style=\"font-family:Cambria;font-size:17px;\">limited source of capital</div>", "<div style=\"font-family:Cambria;font-size:17px;\">high taxation</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Sole proprietors often have difficulty accessing sufficient capital to fund their business operations and expansion because they rely on their personal savings and any profits generated by the business. This can limit their ability to grow and compete effectively in the market. While the other options (high level of risk, limited expertise, and high taxation) can also be challenges for sole proprietors, the limited source of capital is often the most significant issue.</div>", "topic": "BUSINESS ORGANISATION : SOLE PROPRIETOSHIP"}, {"id": "objective>Economics>2009>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A public liability company is run on a daily basis by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the chief executive</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the shareholders</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the board of directors</div>", "<div style=\"font-family:Cambria;font-size:17px;\">financial consultants</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It is established by an Act of parliament, owned by shareholders and control by the board of directors.</div>", "topic": "BUSINESS ORGANISATION : LIMITED LIABILITY COMPANIES"}, {"id": "objective>Economics>2009>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The marketing of agricultural products in Nigeria can be improved by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a massive production of farm produce</div>", "<div style=\"font-family:Cambria;font-size:17px;\">re-establishing the marketing boards</div>", "<div style=\"font-family:Cambria;font-size:17px;\">establishing more agricultural banks</div>", "<div style=\"font-family:Cambria;font-size:17px;\">processing of farm produce</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The marketing of agricultural products can be improved by processing of farm produce. Processing of farm produce adds value to the products, makes them more appealing to consumers, and extends their shelf life. This can lead to increased demand and better prices for the products. The other options do not directly improve the marketing of agricultural products. Massive production of farm produce without corresponding increase in demand can lead to wastage. Re-establishing marketing boards and establishing more agricultural banks can help in the distribution and financing of agricultural products, but they do not directly improve the marketing of the products.</div>", "topic": "AGRICULTURE IN WEST AFRICA : MARKETING BOARDS"}, {"id": "objective>Economics>2009>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">To enhance the competitiveness of domestic agricultural products, there is need to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">ban the importation of agricultural products</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increase the exportation of agricultural products</div>", "<div style=\"font-family:Cambria;font-size:17px;\">improve the quality of domestic agricultural products</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increase the output of domestic agricultural products</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">There is need to improve the quality of domestic agricultural products by improved techniques and practices.</div>", "topic": "AGRICULTURE IN WEST AFRICA : FEATURES"}, {"id": "objective>Economics>2009>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In Nigeria, the location of a steel industry at Ajaokuta is due to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the availability of transport network</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the proximity to source of power</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the proximity to large deposits of iron ore </div>", "<div style=\"font-family:Cambria;font-size:17px;\">political consideration</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The location of iron and steel industry at Ajakuta in Nigeria is best explained by the presence of iron ore at ltakpe and coal at Orukpa and Okaba</div>", "topic": "INDUSTRY & INDUSTRIALISATION : INTRODUCTION"}, {"id": "objective>Economics>2009>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Industries for consumer goods are concentrated in urban centres as a result of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">large market </div>", "<div style=\"font-family:Cambria;font-size:17px;\">power supply</div>", "<div style=\"font-family:Cambria;font-size:17px;\">government policy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">weather conditions</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Consumer goods are highly concentrated in the urban areas as the rise in the income of the middle-income group is one of the major factors for the growth of the market</div>", "topic": "INDUSTRY & INDUSTRIALISATION : COMMERCIALISATION & PRIVATISATION"}, {"id": "objective>Economics>2009>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The current industrial development strategy in Nigeria is aimed at encouraging</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">small-scale industries</div>", "<div style=\"font-family:Cambria;font-size:17px;\">medium-scale industries</div>", "<div style=\"font-family:Cambria;font-size:17px;\">small and medium-scale industries</div>", "<div style=\"font-family:Cambria;font-size:17px;\">medium and large-scale industries</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The economic transformation agenda, otherwise known as Nigeria Vision 20: 2020, sets the direction for the current industrial policy in Nigeria. The industrialization strategy aims at achieving greater global competitiveness in the production of processed and manufactured goods by linking industrial activity with primary sector activity, domestic and foreign trade, and service activity. It aims at encouraging the small and medium-scale industries through various programmes and interventions.</div>", "topic": "INDUSTRY & INDUSTRIALISATION : INDIGENISATION & NATIONALISATION"}, {"id": "objective>Economics>2009>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Activities in the oil and gas industry are classified into</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">oil exploration and distribution</div>", "<div style=\"font-family:Cambria;font-size:17px;\">refining and marketing of finished products</div>", "<div style=\"font-family:Cambria;font-size:17px;\">upstream and downstream</div>", "<div style=\"font-family:Cambria;font-size:17px;\">exploration and drilling</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The oil and gas industry is divided into upstream and downstream oil sector. The upstream oil sector is also commonly known as the exploration and production while the downstream sector commonly refers to the refining of petroleum crude oil and the processing and purifying of raw natural gas,as well as the marketing and distribution of products derived from crude oil and natural gas.</div>", "topic": "PETROLEUM AND THE NIGERIA ECONOMY : INTRODUCTION"}, {"id": "objective>Economics>2009>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">High dependency ratio is influenced by </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">high infant mortality rate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the level of income</div>", "<div style=\"font-family:Cambria;font-size:17px;\">high birth rate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">inadequate medical care for children</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A high dependency ratio means those of working age, and the overall economy, face a greater burden in supporting the aging population. The higher the birth rate, the higher the dependency ratio.</div>", "topic": "POPULATION : DETERMINANTS OF POPULATION SIZE"}, {"id": "objective>Economics>2009>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Occupational distribution of population determines the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">size of a population available and willing to work</div>", "<div style=\"font-family:Cambria;font-size:17px;\">population density of a place</div>", "<div style=\"font-family:Cambria;font-size:17px;\">dependency ratio of a country</div>", "<div style=\"font-family:Cambria;font-size:17px;\">size and categories of the labour force</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The terms occupational structure and occupational distribution indicate the degree of the development and diversification achieved in any economy. Occupational structure refers to the distribution of working population among the different sectors in the economy.It determines the size and categories of the labour force or working population.</div>", "topic": "POPULATION : POPULATION STRUCTURE/ DISTRIBUTION"}, {"id": "objective>Economics>2009>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The mobility of labour is mainly determined by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the age of workers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">government policy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">trade unions </div>", "<div style=\"font-family:Cambria;font-size:17px;\">wage rate differentials</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The mobility of labor refers to the ability of workers to move between different jobs, occupations, industries, or geographical locations in search of employment opportunities. Wage rate differentials, which are variations in wages or salary levels across different jobs or regions, play a crucial role in determining the mobility of labor. <br/>  <br/> When there are significant wage rate differentials between jobs or regions, workers may be motivated to move to areas or industries that offer higher wages. Higher wages can incentivize workers to relocate, switch jobs, or acquire new skills to access better-paying employment opportunities. Conversely, lower wages in certain areas or industries may discourage labor mobility.</div>", "topic": "LABOUR MARKET AND UNEMPLOYMENT : SUPPLY OF LABOUR"}, {"id": "objective>Economics>2009>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When workers have a union, the supply of labour is said to be </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">monopolistic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">oligopolistic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">monopsonistic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">competitive</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The word 'Monopolistic' relates to a person or business that has exclusive possession or control of the supply of or trade in a commodity or service. When workers have a union, the supply of labour is said to be monopolistic.</div>", "topic": "LABOUR MARKET AND UNEMPLOYMENT : INTRODUCTION"}];
